import re
from math import inf

# Parse function definitions
func_defs = []
current_name = None
current_body = []
for line in data.splitlines():
    if line.startswith('def fn_'):
        if current_name:
            func_defs.append((current_name, '\n'.join(current_body)))
        current_name = line.split('(')[0].replace('def ', '')
        current_body = [line]
    elif current_name:
        current_body.append(line)
if current_name:
    func_defs.append((current_name, '\n'.join(current_body)))

print(f"Parsed {len(func_defs)} functions")

# Define correct reference implementations for testing
def ref_dot(a, b):
    return sum(x * y for x, y in zip(a, b))

def ref_is_leap(y):
    return y % 4 == 0 and (y % 100 != 0 or y % 400 == 0)

def ref_clamp(x, lo, hi):
    return lo if x < lo else hi if x > hi else x

def ref_factorial(n):
    out = 1
    for k in range(2, n + 1):
        out *= k
    return out

def ref_reverse_words(s):
    return ' '.join(s.split()[::-1])

def ref_sum_to(n):
    return sum(range(1, n + 1))

def ref_median(xs):
    s = sorted(xs)
    m = len(s) // 2
    return s[m] if len(s) % 2 else (s[m - 1] + s[m]) / 2

def ref_mean(xs):
    return sum(xs) / len(xs)

def ref_max_run(xs):
    best = 0
    cur = 0
    for x in xs:
        if x > 0:
            cur += 1
            best = max(best, cur)
        else:
            cur = 0
    return best

def ref_count_vowels(s):
    return sum(1 for c in s.lower() if c in 'aeiou')

# Map function names to reference implementations and test cases
test_cases = {
    'dot': [(([], []), 0), (([1,2], [3,4]), 11), (([1], [1,2]), 1)],
    'is_leap': [(2000, True), (1900, False), (2024, True), (2023, False)],
    'clamp': [(5, 0, 10, 5), ((-1, 0, 10), 0), ((11, 0, 10), 10)],
    'factorial': [(0, 1), (1, 1), (5, 120)],
    'reverse_words': [('hello world', 'world hello'), ('  a  b ', 'b a')],
    'sum_to': [(0, 0), (1, 1), (3, 6)],
    'median': [([1], 1), ([1,2], 1.5), ([1,2,3], 2), ([1,2,3,4], 2.5)],
    'mean': [([1,2,3], 2.0), ([5], 5.0)],
    'max_run': [([], 0), (([1,2,-1,3,4,5]), 3), (([-1,-2]), 0)],
    'count_vowels': [('hello', 2), ('AEIOU', 5), ('xyz', 0)]
}

bugs = []
for name, code in func_defs:
    # Extract base function name without number
    base = re.sub(r'_\d+$', '', name)
    if base not in test_cases:
        print(f"Unknown function type: {name}")
        continue

    ns = {}
    try:
        exec(code, ns)
        fn = ns[name]
    except Exception as e:
        print(f"Failed to execute {name}: {e}")
        continue

    for inputs, expected in test_cases[base]:
        args = inputs if isinstance(inputs, tuple) else (inputs,)
        try:
            result = fn(*args)
            if result != expected:
                bugs.append((name, base, args, expected, result))
                print(f"BUG: {name}({args}) -> {result}, expected {expected}")
        except Exception as e:
            bugs.append((name, base, args, expected, f"Error: {e}"))
            print(f"ERROR: {name}({args}) raised {e}")

print(f"\nFound {len(bugs)} bugs")
for b in bugs:
    print(b)

